select concat('SQF', DATE_FORMAT(NOW(), '%Y%m%d'), LPAD(next_no, 4, '0')) as apply_no
from (
    select CAST(SUBSTRING(MAX(apply_no), -4) AS UNSIGNED) + 1 as next_no
    from fund_transfer_apply
    where apply_no like concat('SQF', DATE_FORMAT(NOW(), '%Y%m%d'), '%')
) t

